import { Routes, Route } from 'react-router-dom';
import About from './components/About';
import ProductList from './components/ProductList'; // Nhập ProductList
import Gallery from './components/Gallery';

function App() {
  return (
    <div className="App">
      {/* ... header giữ nguyên ... */}
      <main>
        <Routes>
          <Route path="/" element={<About />} />
          <Route path="/products" element={<ProductList />} /> {/* Sử dụng ProductList ở đây */}
          <Route path="/gallery" element={<Gallery />} />
        </Routes>
      </main>
    </div>
  );
}
